1	\chapter{The Jacobian as an abelian variety}
2	\label{chap:Jacobian}
3	
4	Let $C$ be a smooth proper curve over $k$ in the sense of Chapter~\ref{chap:Genus}, with genus $g = g(C)$.
5	
6	Because the Picard-scheme machinery (Chapter~\ref{chap:Picard_Functor}) is blocked at the level of monoidal-category infrastructure for $\mathcal O_X$-modules and the full FGA representability theorem, this chapter builds the Jacobian by an alternative ad-hoc route: the Albanese functor on smooth proper curves.
7	
8	\section{The Albanese construction}
9	
10	For a smooth proper curve $C$ over $k$, the Albanese variety is the universal abelian variety receiving a morphism from $C$. Over an algebraically closed field this is classically identified with the connected component of the identity of the Picard scheme, but we construct it directly from symmetric powers.
11	
12	\subsection{Symmetric powers and the Abel--Jacobi map}
13	
14	Let $C^{(g)} = \Sym^g(C)$ be the $g$\textsuperscript{th} symmetric power of $C$ (the quotient of $C^g$ by the action of the symmetric group $S_g$). It is a smooth proper scheme over $k$ of dimension $g$. Fix a $k$-rational point $P_0 \in C(k)$. The map
15	\[
16	  \sigma \colon C^{(g)} \longrightarrow \Pic^g_{C/k}, \qquad
17	  \sum_{i=1}^g [P_i] \longmapsto \mathcal O_C\bigl(\textstyle\sum_{i=1}^g P_i - g P_0\bigr)
18	\]
19	is surjective and birational onto its image; its fibres are projective spaces (Brill--Noether--Riemann--Roch). Choosing $P_0$ gives a translation isomorphism $\Pic^g_{C/k} \xrightarrow{\;\sim\;} \Pic^0_{C/k}$, and the Stein factorisation of $\sigma$ yields the Jacobian as the connected component of the identity.
20	
21	In the Lean formalisation we do not have general symmetric powers of schemes (or quotients by finite group actions) in Mathlib. We therefore take a more direct approach: we define the Jacobian as the Albanese object of $C$ inside the category of smooth proper group schemes over $k$, using the universal property and the known dimension formula.
22	
23	\subsection{The Albanese universal property}
24	
25	\begin{definition}\leanok
26	[Albanese universal property of a pointed curve]
27	  \label{def:IsAlbanese}
28	  \lean{AlgebraicGeometry.IsAlbanese}
29	  Let $(C, P)$ be a smooth proper geometrically irreducible curve over $k$ with a marked $k$-rational point $P \in C(k)$. A smooth proper geometrically irreducible group scheme $J$ over $k$ is an \emph{Albanese object} for $(C, P)$ if there exists a morphism $\iota \colon C \to J$ sending $P$ to the identity element $\eta \in J$, and such that every morphism $f \colon C \to A$ from $C$ to a smooth proper geometrically irreducible group scheme $A$ with $f(P) = \eta_A$ factors uniquely as $f = \iota \circ g$ for some morphism of group schemes $g \colon J \to A$.
30	\end{definition}
31	
32	\begin{remark}
33	  \label{rem:IsAlbanese_typeclasses}
34	  \uses{def:IsAlbanese}
35	  The Lean encoding of Definition~\ref{def:IsAlbanese} takes the four abelian-variety conditions on $J$ --- group-object structure, properness, smoothness, geometric irreducibility --- as \emph{typeclass parameters} of the declaration \texttt{AlgebraicGeometry.IsAlbanese}, not as conjuncts inside the body. The body is the existential statement on $\iota$ and its universal-factorisation property; the four hypotheses on $J$ sit on the binder of the definition. A downstream user constructs an \texttt{IsAlbanese} term against these instances and threads them at every use site (cf.\ the \texttt{letI} chain in \texttt{AbelJacobi.ofCurve} which installs all four instances on $\Jac(C)$ before applying any Albanese consequence). The same convention is used for the target abelian variety $A$ in the universal-property clause.
36	\end{remark}
37	
38	\subsection{Extracting the universal morphism}
39	
40	An \texttt{IsAlbanese} term $h$ packages, behind a single existential, the universal pointed morphism $\iota \colon C \to J$ together with its two characterising properties: the pointed condition $P \circ \iota = \eta_J$ and the universal-factorisation property of $\iota$. The data and the two properties are extracted from the existential body by the following trio of helpers, each implemented in Lean via \texttt{Classical.choose} / \texttt{Classical.choose\_spec} on the existential content of \texttt{IsAlbanese}.
41	
42	\begin{definition}
43	
44	\leanok
45	[The Albanese universal morphism]
46	  \label{def:IsAlbanese_ofCurve}
47	  \lean{AlgebraicGeometry.IsAlbanese.ofCurve}
48	  \uses{def:IsAlbanese}
49	  Given a pointed curve $(C, P)$ and an Albanese term $h \colon \mathrm{IsAlbanese}\,C\,P\,J$, the \emph{universal morphism} of $h$ is the morphism
50	  \[
51	    \iota := h.\mathtt{ofCurve} \colon C \to J,
52	  \]
53	  obtained by \texttt{Classical.choose} on the existential body of $h$.
54	\end{definition}
55	
56	\begin{lemma}
57	
58	\leanok
59	[Pointed condition for the universal morphism]
60	  \label{lem:IsAlbanese_comp_ofCurve}
61	  \lean{AlgebraicGeometry.IsAlbanese.comp_ofCurve}
62	  \uses{def:IsAlbanese_ofCurve}
63	  The universal morphism $h.\mathtt{ofCurve}$ sends the marked point $P$ to the identity of $J$:
64	  \[
65	    P \circ h.\mathtt{ofCurve} \;=\; \eta_J.
66	  \]
67	\end{lemma}
68	
69	\begin{lemma}
70	
71	\leanok
72	[Universal factorisation through the Albanese object]
73	  \label{lem:IsAlbanese_exists_unique_ofCurve_comp}
74	  \lean{AlgebraicGeometry.IsAlbanese.exists_unique_ofCurve_comp}
75	  \uses{def:IsAlbanese_ofCurve}
76	  For every morphism $f \colon C \to A$ from $C$ to a smooth proper geometrically irreducible group scheme $A$ over $k$ with $P \circ f = \eta_A$, there exists a unique morphism $g \colon J \to A$ such that $f = h.\mathtt{ofCurve} \circ g$.
77	\end{lemma}
78	
79	This extraction API is precisely what the protected interface $\mathtt{Jacobian.ofCurve}$, $\mathtt{Jacobian.comp\_ofCurve}$, $\mathtt{Jacobian.exists\_unique\_ofCurve\_comp}$ of Chapter~\ref{chap:AbelJacobi} consumes: each protected wrapper takes a marked point $P \in C(k)$ as input, projects the per-point Albanese data from the bundled witness \texttt{JacobianWitness} (Definition~\ref{def:JacobianWitness}) at that $P$, and applies the corresponding helper above.
80	
81	\begin{theorem}\leanok
82	[Uniqueness of the Albanese object]
83	  \label{thm:IsAlbanese_unique}
84	  \lean{AlgebraicGeometry.IsAlbanese.unique}
85	  \uses{def:IsAlbanese, def:IsAlbanese_ofCurve}
86	  Let $J_1, J_2$ be two Albanese objects for the same pointed curve $(C, P)$, with universal pointed morphisms $\iota_1 := h_1.\mathtt{ofCurve} \colon C \to J_1$ and $\iota_2 := h_2.\mathtt{ofCurve} \colon C \to J_2$ (Definition~\ref{def:IsAlbanese_ofCurve}). Then there is a unique morphism $e \colon J_1 \to J_2$ satisfying $\iota_2 = \iota_1 \circ e$. The proof is the standard universal-property argument: each of the two universal morphisms factors through the other, the two composites equal the unique self-factorisation $\mathrm{id}$, and the produced morphism $e$ is therefore an isomorphism; only the existence and uniqueness of $e$ as a morphism are exposed in the conclusion (see Remark~\ref{rem:IsAlbanese_unique_iso}).
87	\end{theorem}
88	
89	\begin{remark}
90	  \label{rem:IsAlbanese_unique_iso}
91	  \uses{thm:IsAlbanese_unique}
92	  The Lean proof of Theorem~\ref{thm:IsAlbanese_unique} internally produces an inverse morphism $h \colon J_2 \to J_1$ and verifies $g \circ h = \mathrm{id}_{J_1}$ and $h \circ g = \mathrm{id}_{J_2}$ (the invertibility witnesses are computed as intermediate lemmas of the tactic block) before returning the triple $(g,\ \iota_2 = \iota_1 \circ g,\ \text{uniqueness})$. The invertibility witnesses are computed but not retained in the return type
93	  \[
94	    \exists! (e : J_1 \to J_2),\ \iota_2 = \iota_1 \circ e.
95	  \]
96	  The natural strengthening would be to return
97	  \[
98	    \exists! (e : J_1 \cong J_2),\ \iota_2 = \iota_1 \circ e.\mathtt{hom},
99	  \]
100	  packaging the produced morphism together with its inverse. Tightening the conclusion in this way is a Lean-side refactor of the signature of \texttt{IsAlbanese.unique} that the project may carry out in a future iteration. The downstream consumers of \texttt{IsAlbanese.unique} (the protected \texttt{AbelJacobi.Jacobian.*} interface) use only the morphism-and-uniqueness content of the conclusion, so the current weaker conclusion is sufficient for the present API.
101	\end{remark}
102	
103	\subsection{The Jacobian definition}
104	
105	\begin{definition}\leanok
106	[Jacobian]
107	  \label{def:Jacobian}
108	  \lean{AlgebraicGeometry.Jacobian}
109	  \uses{def:genus, def:IsAlbanese, def:JacobianWitness, thm:nonempty_jacobianWitness}
110	  The \emph{Jacobian} of $C$ is the abelian variety $\Jac(C)$ over $k$ obtained as the Albanese object of $C$: a smooth proper geometrically irreducible group scheme over $k$ of dimension $g(C)$ equipped with a universal morphism $C \to \Jac(C)$ (for each choice of marked point). It is viewed as an object of the category of $k$-schemes over $\Spec k$. Formally, $\Jac(C)$ is defined as the underlying scheme of a (uniform-over-$P$) Albanese witness for $C$ provided by Theorem~\ref{thm:nonempty_jacobianWitness}.
111	
112	  When $g(C) = 0$ the Jacobian collapses to $\Spec k$ itself, which is the terminal object in the category of $k$-schemes. When $g(C) > 0$ the underlying scheme is the abelian variety produced by Theorem~\ref{thm:nonempty_jacobianWitness}; the genus-one case recovers $C$ itself (after choosing a $k$-rational point), and the higher genus case yields the non-trivial $g$-dimensional abelian variety. Both cases are handled uniformly: $\Jac(C)$ is the underlying scheme of the Albanese witness, with no special-case branching at the level of the definition. The genus-$0$ specialisation is implicit in the fact that any group scheme over $k$ of relative dimension $0$ is isomorphic to $\Spec k$.
113	\end{definition}
114	
115	\section{Group scheme structure and abelian-variety properties}
116	
117	The four protected instances on $\Jac(C)$ are each obtained, at the level of the Lean formalisation, by projecting a field of the underlying Albanese witness produced by Theorem~\ref{thm:nonempty_jacobianWitness}. The mathematical content of each property is the corresponding statement about the Albanese variety of a smooth proper geometrically irreducible curve.
118	
119	\begin{theorem}\leanok
120	[Group object structure]
121	  \label{thm:Jacobian_grpObj}
122	  \lean{AlgebraicGeometry.Jacobian.instGrpObj}
123	  \uses{def:Jacobian}
124	  $\Jac(C)$ carries a canonical group-object structure in the category of $k$-schemes over $\Spec k$.
125	\end{theorem}
126	
127	\begin{proof}
128	  \uses{def:Jacobian, thm:nonempty_jacobianWitness, thm:IsAlbanese_unique}
129	  \leanok
130	  By Definition~\ref{def:Jacobian}, $\Jac(C) = (\mathrm{jacobianWitness}\, C).J$ as a $k$-scheme, where $\mathrm{jacobianWitness}\, C$ is the Albanese witness extracted from Theorem~\ref{thm:nonempty_jacobianWitness} via \texttt{Classical.choice}. The witness carries the group-object structure as its field $\mathtt{grpObj} : \mathrm{GrpObj}\, J$, so $\Jac(C)$ inherits it by projection.
131	
132	  Mathematically, any Albanese variety carries a unique group-object structure compatible with its universal pointed morphism. Indeed, if $\iota \colon C \to J$ is the universal morphism sending the marked point $P$ to the identity, then the diagonal $C \times C \to J \times J$, post-composed with the universal morphism out of $C \times C$ (factored through $J$ by Theorem~\ref{thm:IsAlbanese_unique}), produces the multiplication; the unique morphism to a one-point pointed scheme produces the inverse; the marked point produces the identity. Uniqueness of the resulting group-object structure is again the universal-property argument of Theorem~\ref{thm:IsAlbanese_unique}.
133	\end{proof}
134	
135	\begin{theorem}\leanok
136	[Smoothness and dimension]
137	  \label{thm:Jacobian_smooth_genus}
138	  \lean{AlgebraicGeometry.Jacobian.smoothOfRelativeDimension_genus}
139	  \uses{def:Jacobian, def:genus}
140	  $\Jac(C) \to \Spec k$ is smooth of relative dimension $g(C)$.
141	\end{theorem}
142	
143	\begin{proof}
144	  \uses{def:Jacobian, thm:nonempty_jacobianWitness, def:genus}
145	  \leanok
146	  The Lean formalisation projects the field $\mathtt{smoothGenus} : \mathrm{SmoothOfRelativeDimension}\,(\genus\, C)\,J.\mathtt{hom}$ of the witness $\mathrm{jacobianWitness}\, C$; the relative dimension $g(C)$ is recorded directly in the witness so that no separate dimension calculation is needed on the Lean side.
147	
148	  Mathematically, the dimension of an Albanese variety of $C$ equals the genus $g = g(C) = \dim_k H^1(C, \mathcal O_C)$ (Phase~A, Chapter~\ref{chap:Cohomology_StructureSheafAb}). The tangent space to $\Jac(C)$ at the identity is canonically identified with $H^1(C, \mathcal O_C)$ by deformation theory of the Picard functor: an infinitesimal deformation of $\mathcal O_C$ is classified by an element of $H^1(C, \mathcal O_C)$, and this identifies the tangent space at the identity of $\Pic^0_{C/k}$ with $H^1(C, \mathcal O_C)$. Smoothness of $\Jac(C)$ over $k$ follows from the smoothness of any group scheme over a field whose tangent space at the identity is of constant rank equal to the relative dimension --- a consequence of homogeneity of the group action, since translation by any $k$-rational point is an automorphism and so the local structure of $\Jac(C)$ at every $k$-rational point is the same as at the identity.
149	\end{proof}
150	
151	\begin{theorem}\leanok
152	[Properness]
153	  \label{thm:Jacobian_proper}
154	  \lean{AlgebraicGeometry.Jacobian.instIsProper}
155	  \uses{def:Jacobian}
156	  $\Jac(C) \to \Spec k$ is proper.
157	\end{theorem}
158	
159	\begin{proof}
160	  \uses{def:Jacobian, thm:nonempty_jacobianWitness}
161	  \leanok
162	  The Lean formalisation projects the field $\mathtt{proper} : \mathrm{IsProper}\, J.\mathtt{hom}$ of the witness.
163	
164	  Mathematically, properness of the Albanese variety is part of its construction. In the Picard-scheme route, $\Pic^0_{C/k}$ is a closed subgroup scheme of the relative Picard scheme $\Pic_{C/k}$, which is itself proper over $\Spec k$ because $C$ is proper and geometrically connected (FGA representability for $\Pic$ of a smooth proper geometrically connected curve produces a proper group scheme; cf.\ FGA Explained, Chapter~9). In the symmetric-power route, properness of $\Pic^g_{C/k}$ (and hence $\Pic^0_{C/k}$ after translation) follows from properness of $\Sym^g(C)$ together with the universal closedness of the surjection $\sigma$. In either case, properness descends to $\Jac(C)$.
165	\end{proof}
166	
167	\begin{theorem}\leanok
168	[Geometric irreducibility]
169	  \label{thm:Jacobian_geomIrred}
170	  \lean{AlgebraicGeometry.Jacobian.instGeometricallyIrreducible}
171	  \uses{def:Jacobian}
172	  $\Jac(C) \to \Spec k$ is geometrically irreducible.
173	\end{theorem}
174	
175	\begin{proof}
176	  \uses{def:Jacobian, thm:nonempty_jacobianWitness}
177	  \leanok
178	  The Lean formalisation projects the field $\mathtt{geomIrred} : \mathrm{GeometricallyIrreducible}\, J.\mathtt{hom}$ of the witness.
179	
180	  Mathematically, the Albanese variety $\Jac(C)$ is the identity component of $\Pic_{C/k}$ (the Picard scheme), and the identity component of a group scheme of finite type over a field is geometrically irreducible (in fact, geometrically connected, and since it is smooth at the identity by Theorem~\ref{thm:Jacobian_smooth_genus} it is geometrically irreducible). Equivalently, in the symmetric-power route, $\Jac(C)$ arises as the Stein factorisation of $\Sym^g(C) \to \Pic^g_{C/k}$ followed by a translation; $\Sym^g(C)$ is geometrically irreducible (being the quotient of $C^g$, itself geometrically irreducible as a product of geometrically irreducible factors, by a finite group action), so its image under the Stein factorisation is geometrically irreducible as well.
181	\end{proof}
182	
183	\subsection{Sanity check in low genus}
184	
185	\begin{itemize}
186	  \item $g = 0$: Then $\Jac(C) = \Spec k$, the trivial group scheme; $\Jac(\mathbb P^1_k) = \Spec k$ is smooth of relative dimension $0 = g$.
187	  \item $g = 1$: Then $\Jac(C) \cong C$ once a $k$-rational point on $C$ is fixed; $C$ is itself an elliptic curve (abelian variety of dimension $1$).
188	  \item $g \ge 2$: $\Jac(C)$ is a non-trivial $g$-dimensional abelian variety, never isomorphic to $C$ as a scheme.
189	\end{itemize}
190	
191	\section{Existence of an Albanese variety}
192	
193	The classical construction of the Jacobian goes through the Picard scheme machinery: $\Jac(C)$ is the connected component of the identity of $\Pic^0_{C/k}$. An equivalent route, available whenever a $k$-rational point $P \in C(k)$ has been fixed, is to take the Stein factorisation of the Abel--Jacobi morphism $\Sym^g(C) \to \Pic^g_{C/k}$ and translate by $-gP$.
194	
195	\subsection{The Albanese witness bundle}
196	
197	Before stating the existence theorem, we package its conclusion into a single structure --- the \emph{Albanese witness} of $C$. This bundling reverses the quantifier order of the classical statement (see Remark~\ref{rem:JacobianWitness_quantifier_order}) and is the data structure consumed by the \texttt{Jacobian} family of declarations in this file and by the \texttt{AbelJacobi} interface of Chapter~\ref{chap:AbelJacobi}.
198	
199	\begin{definition}
200	
201	\leanok
202	[Albanese witness for a curve]
203	  \label{def:JacobianWitness}
204	  \lean{AlgebraicGeometry.JacobianWitness}
205	  \uses{def:IsAlbanese, def:genus}
206	  An \emph{Albanese witness} for the smooth proper geometrically irreducible curve $C$ over $k$ is a bundle of the following seven fields:
207	  \begin{itemize}
208	    \item $J$: an object of the category of $k$-schemes over $\Spec k$ --- the candidate Albanese object.
209	    \item $\mathtt{grpObj}$: a group-object structure on $J$ in the category of $k$-schemes over $\Spec k$.
210	    \item $\mathtt{proper}$: a proof that the structure morphism $J \to \Spec k$ is proper.
211	    \item $\mathtt{smooth}$: a proof that the structure morphism $J \to \Spec k$ is smooth.
212	    \item $\mathtt{geomIrred}$: a proof that the structure morphism $J \to \Spec k$ is geometrically irreducible.
213	    \item $\mathtt{smoothGenus}$: a proof that the structure morphism $J \to \Spec k$ is smooth of relative dimension $g(C)$. This refines $\mathtt{smooth}$ at the specific relative dimension $\genus\, C$ (see Remark~\ref{rem:JacobianWitness_smooth_redundancy}).
214	    \item $\mathtt{isAlbaneseFor}$: a proof that, for every $k$-rational marked point $P \in C(k)$, the scheme $J$ together with its group-object, proper, smooth, and geometrically-irreducible structures satisfies the Albanese universal property for the pointed curve $(C, P)$ in the sense of Definition~\ref{def:IsAlbanese}.
215	  \end{itemize}
216	  Formally, an Albanese witness is a Lean-level record (a structure) whose name is \texttt{JacobianWitness}.
217	\end{definition}
218	
219	\begin{remark}
220	  \label{rem:JacobianWitness_quantifier_order}
221	  \uses{def:JacobianWitness}
222	  The classical phrasing of the existence statement of an Albanese variety is
223	  \[
224	    \forall\, P \in C(k),\ \exists\, J,\ J \text{ is an Albanese object for } (C, P).
225	  \]
226	  The witness bundle reverses these quantifiers: a single $J$ is chosen once (intrinsic to $C$), and the marked-point-dependent data is recorded as the family-valued field
227	  \[
228	    \mathtt{isAlbaneseFor} \colon \forall\, P \in C(k),\ \mathrm{IsAlbanese}\,C\,P\,J.
229	  \]
230	  Mathematically this reversal is justified because the underlying scheme of any Albanese object is intrinsic to $C$: a different choice of $P \in C(k)$ alters the universal morphism $\iota_P \colon C \to J$ by a translation of $J$, which is an automorphism of $J$, and so leaves $J$ unchanged as a scheme. The reversed bundling is what makes the per-$P$ projection in Chapter~\ref{chap:AbelJacobi} clean: $\mathtt{Jacobian.ofCurve}$, $\mathtt{Jacobian.comp\_ofCurve}$, and $\mathtt{Jacobian.exists\_unique\_ofCurve\_comp}$ each take a marked point $P$ as input and project the corresponding component of $\mathtt{isAlbaneseFor}\,P$ via the extraction trio (Definition~\ref{def:IsAlbanese_ofCurve}, Lemmas~\ref{lem:IsAlbanese_comp_ofCurve}, \ref{lem:IsAlbanese_exists_unique_ofCurve_comp}).
231	\end{remark}
232	
233	\begin{remark}
234	  \label{rem:JacobianWitness_smooth_redundancy}
235	  \uses{def:JacobianWitness}
236	  The fields $\mathtt{smooth}$ and $\mathtt{smoothGenus}$ of an Albanese witness are mathematically redundant: the relative-dimension version implies the unqualified version via Mathlib's \texttt{AlgebraicGeometry.SmoothOfRelativeDimension.smooth}. Keeping both fields is a Lean-level convenience: $\mathtt{smooth}$ is the form required by the typeclass binder of \texttt{IsAlbanese} (and by the protected $\mathtt{Jacobian.instGrpObj}$ projection), whereas $\mathtt{smoothGenus}$ is the form required by the protected $\mathtt{Jacobian.smoothOfRelativeDimension\_genus}$ projection. The redundancy carries no mathematical cost (the two fields agree) and no soundness cost (deriving one from the other would only re-run the same Mathlib instance synthesis at the projection sites).
237	\end{remark}
238	
239	\begin{theorem}\leanok
240	[Existence of an Albanese variety uniformly over the marked point]
241	  \label{thm:nonempty_jacobianWitness}
242	  \lean{AlgebraicGeometry.nonempty_jacobianWitness}
243	  \uses{def:IsAlbanese, def:Jacobian, def:genus, def:JacobianWitness}
244	  Let $C$ be a smooth proper geometrically irreducible curve over a field $k$. There exists a smooth proper geometrically irreducible group scheme $J$ over $k$ of relative dimension $g(C)$ such that, for every $k$-rational point $P \in C(k)$, the scheme $J$ is an Albanese object for the pointed curve $(C, P)$ in the sense of Definition~\ref{def:IsAlbanese}. Equivalently, the type of Albanese witnesses for $C$ (Definition~\ref{def:JacobianWitness}) is non-empty.
245	\end{theorem}
246	
247	\begin{proof}
248	  \uses{def:IsAlbanese, def:genus}
249	  \leanok
250	  The proof is split into three classical constructions plus the genus-$0$ sub-case absorbed into the same witness. Each route produces the same intrinsic scheme $J$; only the universal morphism $\iota_P \colon C \to J$ varies with the marked point $P$. We outline each route and name the Mathlib infrastructure each one requires.
251	
252	  \paragraph{(0) Reduction to a $P$-independent witness.}
253	  The witness $J$ depends only on $C$, not on the marked point $P$. Indeed, both classical constructions below produce $J$ as an intrinsic object of $C$ (the identity component of $\Pic_{C/k}$, or the Stein-factorisation target of $\Sym^g(C) \to \Pic^g_{C/k}$ translated by a fixed $P_0$); a different choice of $P$ in $C(k)$ alters $\iota_P$ by a translation of $J$, which is an automorphism, and so does not change $J$ as a scheme. The Lean encoding reflects this by bundling $J$ as a single field and the universal-property data as $\forall P,\, \mathrm{IsAlbanese}\, C\, P\, J$. We now turn to producing $J$.
254	
255	  \paragraph{Route A --- Picard scheme.}
256	  This route follows Hartshorne~III.4 and FGA Explained, Chapter~9.
257	
258	  \begin{itemize}
259	    \item[\textbf{(A.1)}] \emph{The relative Picard functor.} For a $k$-scheme $T$, write $C_T := C \times_k T$ and let $\pi \colon C_T \to T$ be the projection. The relative Picard functor is
260	    \[
261	      \Pic^{\sharp}_{C/k} \colon (\Sch/k)^{\mathrm{op}} \to \Sets, \qquad
262	      T \longmapsto \Pic(C_T) / \pi^*\Pic(T).
263	    \]
264	    A $T$-point is a line bundle on $C_T$ modulo a line bundle pulled back from $T$. The set-valued formulation suffices for representability; the canonical abelian-group structure on $\Pic(C_T)$ descends to the quotient by $\pi^*\Pic(T)$ and gives $\Pic^{\sharp}_{C/k}$ a natural group-functor refinement.
265	
266	    \item[\textbf{(A.2)}] \emph{Representability.} For $C$ smooth proper geometrically connected over $k$ with a $k$-rational point, $\Pic^{\sharp}_{C/k}$ (after \'etale sheafification, if $k$ is not algebraically closed) is representable by a $k$-group scheme $\Pic_{C/k}$, locally of finite type. This is FGA's main representability theorem (Grothendieck, FGA~232); the smooth-proper-geometrically-connected hypothesis ensures that the cohomology-and-base-change machinery applies and that $H^0(C, \mathcal O_C) = k$, which is needed for the quotient by $\pi^*\Pic(T)$ to be \'etale-locally injective.
267	
268	    \item[\textbf{(A.3)}] \emph{The identity component.} Let $\Pic^0_{C/k}$ be the identity component of $\Pic_{C/k}$. As the identity component of a $k$-group scheme locally of finite type, $\Pic^0_{C/k}$ is geometrically irreducible; for $C$ smooth proper of genus $g$, it is moreover a smooth proper $k$-group scheme of dimension $g$. Smoothness comes from the deformation-theoretic identification of its tangent space at the identity with $H^1(C, \mathcal O_C)$ and homogeneity of the group action; properness from the fact that the natural map $\Pic^0_{C/k} \to \Pic_{C/k}$ is an open and closed immersion onto a proper component (a consequence of the cohomological criterion: $\Pic^0_{C/k}$ is the kernel of the degree map $\Pic_{C/k} \to \underline{\mathbb Z}_k$, which is locally constant). Take $J := \Pic^0_{C/k}$.
269	
270	    \item[\textbf{(A.4)}] \emph{The Abel--Jacobi universal morphism.} For each $P \in C(k)$, the Abel--Jacobi morphism
271	    \[
272	      \iota_P \colon C \to \Pic^0_{C/k}, \qquad
273	      Q \longmapsto [\mathcal O_C(Q - P)]
274	    \]
275	    sends $P$ to the identity of $\Pic^0_{C/k}$. It is universal among morphisms $f \colon C \to A$ to smooth proper geometrically irreducible $k$-group schemes $A$ with $f(P) = \eta_A$: this is the classical Albanese property of $\Pic^0_{C/k}$, proved by reducing to the case $k = \overline k$ (Galois descent), where it is a standard consequence of the autoduality of the Jacobian and the fact that line bundles on $C \times A$ trivialised along $\{P\} \times A$ correspond bijectively to morphisms $C \to A^{\vee} = A$ sending $P$ to $\eta_A$.
276	  \end{itemize}
277	
278	  \emph{Mathlib status for Route A.} Each sub-step is missing.
279	  \begin{itemize}
280	    \item Sub-step A.1 requires a working theory of relative line bundles on a product $C \times_k T$ and the descent of the abelian-group structure on $\Pic$ along $\pi^*$. The pieces are present individually but not assembled.
281	    \item Sub-step A.2 requires FGA representability for $\Pic_{C/k}$, which in turn requires Hilbert / Quot scheme infrastructure not in Mathlib (\texttt{HilbertScheme}, \texttt{QuotScheme}, and the cohomology-and-base-change for proper morphisms with finitely presented kernels).
282	    \item Sub-step A.3 requires connectedness machinery for group schemes locally of finite type, the identity-component construction $G^0 \subseteq G$, and the degree map $\Pic_{C/k} \to \underline{\mathbb Z}_k$.
283	    \item Sub-step A.4 requires the universal property of $\Pic^0_{C/k}$, which is the classical Albanese functoriality and is not in Mathlib in this form.
284	  \end{itemize}
285	
286	  \paragraph{Route B --- Symmetric powers and Stein factorisation.}
287	  This route follows Milne's \emph{Abelian Varieties} (Chapter~III) and avoids FGA representability at the cost of requiring quotients of schemes by finite group actions.
288	
289	  \begin{itemize}
290	    \item[\textbf{(B.1)}] \emph{The $g$-fold symmetric power.} Form the product $C^g$ and let $S_g$ act by permutation of the factors. The categorical quotient $C^{(g)} := C^g / S_g$ exists as a $k$-scheme, smooth and proper over $k$ of dimension $g$. Smoothness follows because the action of $S_g$ on the smooth $k$-scheme $C^g$ is free outside the diagonal locus and the local-ring computation at the diagonal points produces a smooth ring (this is the symmetric-product computation of Fogarty / Mumford). Properness descends from properness of $C^g$ via the geometric-quotient property.
291	
292	    \item[\textbf{(B.2)}] \emph{The Abel--Jacobi morphism on symmetric powers.} Fix a $k$-rational point $P_0 \in C(k)$. The map
293	    \[
294	      \sigma \colon C^{(g)} \longrightarrow \Pic^g_{C/k}, \qquad
295	      \sum_{i=1}^g [Q_i] \longmapsto \mathcal O_C\bigl(\textstyle\sum_{i=1}^g Q_i\bigr)
296	    \]
297	    is well-defined (the right-hand side is symmetric in the $Q_i$ and depends only on the unordered tuple) and is surjective. By Brill--Noether--Riemann--Roch, $\sigma$ is birational onto its image: a generic divisor of degree $g$ on $C$ has $h^0(\mathcal O_C(D)) = 1$, so the fibre $\sigma^{-1}([\mathcal O_C(D)])$ is a point at generic divisors; the special fibres are projective spaces $\mathbb P(h^0 - 1)$ over the locus where $h^0 > 1$.
298	
299	    \item[\textbf{(B.3)}] \emph{The Stein factorisation.} Because $\sigma$ is a proper surjection with geometrically connected fibres (each fibre $\mathbb P^{h^0-1}_k$ is geometrically irreducible), its Stein factorisation
300	    \[
301	      C^{(g)} \xrightarrow{\;\sigma_*\;} \Spec_{\Pic^g_{C/k}}\bigl(\sigma_* \mathcal O_{C^{(g)}}\bigr) \longrightarrow \Pic^g_{C/k}
302	    \]
303	    presents the second arrow as a finite morphism whose source is the intermediate scheme. Since the fibres of $\sigma$ are connected, this intermediate scheme equals $\Pic^g_{C/k}$ scheme-theoretically (the Stein factorisation is trivial on the second arrow when fibres are connected, by Stein's classical theorem). The middle scheme is therefore $\Pic^g_{C/k}$ itself, which is smooth proper geometrically irreducible of dimension $g$. Translating by $-g P_0$ yields $\Pic^0_{C/k}$, and we take $J := \Pic^0_{C/k}$ as in Route A. The universal property is then established as in Sub-step A.4.
304	  \end{itemize}
305	
306	  \emph{Mathlib status for Route B.} Each sub-step is blocked by a different missing piece.
307	  \begin{itemize}
308	    \item Sub-step B.1 requires symmetric powers of schemes (the construction $\Sym^g$ for a $k$-scheme of finite type) and finite-group-scheme quotients of schemes (the quotient $C^g / S_g$). Mathlib has finite-group quotients of types and of various algebraic structures, but not yet a usable scheme-level quotient by a finite group action with the smooth-target property.
309	    \item Sub-step B.2 requires Brill--Noether--Riemann--Roch, including the relative version for families of curves --- the cohomology-and-base-change machinery for proper morphisms.
310	    \item Sub-step B.3 requires the Stein factorisation theorem for proper morphisms of locally Noetherian schemes ($f \colon X \to Y$ proper $\implies$ $f_* \mathcal O_X$ is a coherent $\mathcal O_Y$-algebra). Mathlib has partial coherence-theoretic infrastructure but does not yet have the cohomology of $\mathcal O$-modules of finite type along proper morphisms in the form needed.
311	  \end{itemize}
312	
313	  \paragraph{Genus-$0$ sub-case (absorbed into the same witness).}
314	  When $g(C) = 0$ the witness's underlying scheme is $J = \Spec k$, and the universal property reduces to a rigidity statement.
315	
316	  \begin{itemize}
317	    \item[\textbf{(C.1)}] \emph{Brauer--Severi identification.} A smooth proper geometrically irreducible curve $C$ over $k$ with $g(C) = 0$ and a $k$-rational point $P \in C(k)$ is isomorphic to $\mathbb P^1_k$. This is the Brauer--Severi triviality criterion: a Brauer--Severi variety of dimension $1$ is $\mathbb P^1$ over its base if and only if it has a rational point. The genus-$0$ identification on the curve side uses $h^0(C, \mathcal O_C(P)) = 2$ (Riemann--Roch) to produce a degree-$1$ morphism $C \to \mathbb P^1_k$, which is then an isomorphism by degree-and-dimension.
318	
319	    \item[\textbf{(C.2)}] \emph{Rigidity for morphisms from $\mathbb P^1_k$ to an abelian variety.} Let $A$ be a smooth proper geometrically irreducible group scheme over $k$ and let $f \colon \mathbb P^1_k \to A$ satisfy $f(P) = \eta_A$ for some $P \in \mathbb P^1_k(k)$. Then $f$ is the constant morphism at $\eta_A$. Equivalently, $\Hom(\mathbb P^1_k, A) = A(k)$, with the bijection sending a constant morphism to its value. The classical proof uses the rigidity lemma: any morphism from a proper geometrically connected variety with a $k$-rational point to a separated $k$-scheme that contracts a fibre to a point is constant; for $\mathbb P^1_k \to A$ this fibre is all of $\mathbb P^1_k$ over the identity of $A$.
320	
321	    \item[\textbf{(C.3)}] \emph{The trivial witness.} Take $J := \Spec k$, the terminal $k$-scheme. The group-object structure on $\Spec k$ is trivial; it is smooth proper geometrically irreducible of relative dimension $0 = g(C)$. The unique morphism $\iota_P \colon C \to \Spec k$ sends $P$ to the (unique) point. By Sub-step C.2 every $f \colon C \to A$ with $f(P) = \eta_A$ is constant at $\eta_A$, hence factors uniquely through the unique morphism $g \colon \Spec k \to A$ sending the point to $\eta_A$; uniqueness of $g$ follows because $\Spec k \to A$ is determined by its value on the unique $k$-rational point of $\Spec k$.
322	  \end{itemize}
323	
324	  \emph{Mathlib status for the genus-$0$ sub-case.}
325	  \begin{itemize}
326	    \item Sub-step C.1 requires the genus-$0$ identification on the curve side, which in turn requires Serre duality / the basic Riemann--Roch infrastructure that this project has explicitly trimmed (see the project's Phase~C exit policy). Mathlib has partial $\mathbb P^1$-theory but the curve-side genus-$0$ identification is missing.
327	    \item Sub-step C.2 is the rigidity theorem $\Hom(\mathbb P^1_k, A) = A(k)$, which is not in Mathlib in the form needed here. The general rigidity lemma (\texttt{Mumford rigidity}) for proper geometrically connected morphisms with a rational point exists in this project as Chapter~\ref{chap:Rigidity}, but the specialisation to $\mathbb P^1_k \to A$ requires the prior step C.1.
328	    \item Sub-step C.3 is unconditional once C.1 and C.2 are in place.
329	  \end{itemize}
330	
331	  \paragraph{Mathlib infrastructure summary.}
332	  Three independent Mathlib build-outs each unlock one route of the proof:
333	  \begin{itemize}
334	    \item[\textbf{($\alpha$)}] \emph{Hilbert / Quot scheme infrastructure plus FGA representability}: unlocks Route A. The single highest-cost build-out, since Hilbert/Quot schemes are upstream of much of modern algebraic geometry; but once present, the rest of Route A (identity component, smoothness, properness, universal property) follows by classical arguments already widely formalised in adjacent settings.
335	    \item[\textbf{($\beta$)}] \emph{Symmetric powers of schemes plus finite-group-scheme quotients plus Stein factorisation for proper morphisms (with its cohomology-of-$\mathcal O_X$-modules hypotheses)}: unlocks Route B. Each piece is a meaningful Mathlib contribution in its own right; the bottleneck is the smooth-quotient property of $C^g / S_g$.
336	    \item[\textbf{($\gamma$)}] \emph{The rigidity theorem $\Hom(\mathbb P^1_k, A) = A(k)$ together with the genus-$0$ identification $C \cong \mathbb P^1_k$ for a smooth proper geometrically irreducible curve with a $k$-rational point}: this is a prerequisite of the genus-$0$ sub-case under either Route A or Route B. Independently of ($\alpha$) and ($\beta$), establishing ($\gamma$) lets the genus-$0$ part of the witness be discharged unconditionally; the higher-genus part of the witness then remains under ($\alpha$) or ($\beta$).
337	  \end{itemize}
338	
339	  In sum: Mathlib currently contains none of the three infrastructure builds, and so the existence statement is recorded here as the project's single explicit foundational hypothesis. It backs all downstream consequences --- the four protected instances on $\Jac(C)$ (Theorems~\ref{thm:Jacobian_grpObj}--\ref{thm:Jacobian_geomIrred}), and the Abel--Jacobi map and its universal property of Chapter~\ref{chap:AbelJacobi} --- and is discharged by any one of the three routes above once the corresponding Mathlib infrastructure lands.
340	\end{proof}
341	
342	\section{Implementation route via the Albanese functor}
343	
344	Because the full Picard-scheme representability theorem is not available in current Mathlib, the formal construction proceeds in two layers:
345	
346	\begin{enumerate}
347	  \item \textbf{Layer I --- direct definition.} The Jacobian of $C$ is defined uniformly as the underlying scheme of the Albanese witness provided by Theorem~\ref{thm:nonempty_jacobianWitness}, carrying the four properties of Theorems~\ref{thm:Jacobian_grpObj}--\ref{thm:Jacobian_geomIrred} (each obtained by projection from the witness). The genus-$0$ case is included: the witness's universal property in that case implicitly carries the rigidity content $\Hom(\mathbb P^1_k, A) = A(k)$.
348	
349	  \item \textbf{Layer II --- Abel--Jacobi compatibility.} Chapter~\ref{chap:AbelJacobi} introduces the Abel--Jacobi morphism $C \to \Jac(C)$ and shows that it is universal among morphisms from $C$ to abelian varieties.
350	\end{enumerate}
351

1	\chapter{Sheaf condition along the structure-sheaf forget composite}
2	\label{chap:Cohomology_SheafCompose}
3	
4	This chapter records the first step of Phase~A: equipping the abstract sheaf-cohomology pipeline with the link it needs to compute $H^1(C, \mathcal O_C)$ as an abelian group. It is the smallest unblocking unit of progress toward the genus of a smooth proper curve (Definition~\ref{def:genus}).
5	
6	The chapter introduces no protected declarations: every definition and lemma here is auxiliary, supporting the construction of $H^1(C, \mathcal O_C)$ in subsequent Phase~A iterations.
7	
8	\section{Statement}
9	
10	The structure sheaf $\mathcal O_C$ of a scheme is delivered as a sheaf of commutative rings. To plug it into the cohomology API, which is formulated for sheaves of abelian groups, one must first transport the sheaf condition along the forgetful composite $\mathrm{CommRing} \to \mathrm{Ring} \to \mathrm{Ab}$. The following theorem packages exactly this transport.
11	
12	\begin{theorem}\leanok
13	[Sheaf condition transports along the structure-sheaf forget composite]
14	  \label{thm:HasSheafCompose_forget}
15	  \lean{AlgebraicGeometry.Cohomology.instHasSheafCompose_forget_CommRing_AddCommGrp}
16	  Let $X$ be a topological space. Then the Grothendieck topology of opens of $X$ transports sheaves along the forgetful composite from commutative rings to abelian groups.
17	\end{theorem}
18	
19	\begin{proof}
20	
21	
22	\leanok
23	  Both forgetful functors in the composite $\mathrm{CommRing} \to \mathrm{Ring} \to \mathrm{Ab}$ create (in particular preserve) all small limits. The sheaf condition for the topology of opens is expressed as preservation of certain multiequalizer limits. Composing two limit-preserving functors gives a limit-preserving functor, so post-composition with the forget composite preserves the sheaf condition.
24	\end{proof}
25	
26	\section{Use in the project}
27	
28	Theorem~\ref{thm:HasSheafCompose_forget} is the gateway to:
29	\begin{itemize}
30	  \item constructing $\mathcal O_C$ as a sheaf of abelian groups on $C$;
31	  \item plugging that sheaf into the abstract cohomology functor once sheafification and $\Ext$ are available (Phase~A steps 2--3);
32	  \item endowing the resulting $H^1$ with a $k$-vector-space structure via the $k$-algebra structure on $\Gamma(C, \mathcal O_C)$ (Phase~A step~4);
33	  \item finite-dimensionality via Serre's theorem on coherent cohomology of proper $k$-schemes (Phase~A step~5).
34	\end{itemize}
35	
36	The chain is: sheaf-compose transport (this chapter) $\to$ sheafification $\to$ $\Ext$ $\to$ $k$-module structure on $H^1$ $\to$ Serre finiteness $\to$ genus.
37	
38	\begin{remark}[Lean implementation]
39	  In Lean the forget composite is written as the concatenation of the two structure-forgetful functors $\mathrm{CommRingCat} \to \mathrm{RingCat} \to \mathrm{AddCommGrpCat}$. The proof appeals to the general fact that a functor preserving limits of a given size preserves the sheaf condition when post-composed with a presheaf. The instance body is a 5-line composition of Mathlib's limit-preservation lemmas.
40	\end{remark}
41

